// MARK: - Models

struct Stock: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Double
    var changePercent: Double
    var volume: Int64
    
    enum CodingKeys: String, CodingKey {
        case id, symbol, name
        case currentPrice = "current_price"
        case changePercent = "change_percent"
        case volume
    }
}

struct Trade: Codable, Identifiable {
    let id: String
    let stockSymbol: String
    let type: TradeType
    let quantity: Int
    let price: Double
    let timestamp: Date
    var status: TradeStatus
    
    enum TradeType: String, Codable {
        case buy, sell
    }
    
    enum TradeStatus: String, Codable {
        case pending, executed, failed, cancelled
    }
}

struct Portfolio: Codable {
    var holdings: [Holding]
    var cashBalance: Double
    var totalValue: Double {
        holdings.reduce(cashBalance) { $0 + ($1.quantity * $1.currentPrice) }
    }
    var totalGainLoss: Double {
        holdings.reduce(0) { $0 + (($1.currentPrice - $1.averagePrice) * Double($1.quantity)) }
    }
}

struct Holding: Codable, Identifiable {
    let id: String
    let stockSymbol: String
    var quantity: Int
    var averagePrice: Double
    var currentPrice: Double
    
    var totalValue: Double {
        Double(quantity) * currentPrice
    }
    
    var gainLoss: Double {
        (currentPrice - averagePrice) * Double(quantity)
    }
    
    var gainLossPercent: Double {
        ((currentPrice - averagePrice) / averagePrice) * 100
    }
}

struct TradeOrder {
    let stockSymbol: String
    let type: Trade.TradeType
    let quantity: Int
    let orderType: OrderType
    let limitPrice: Double?
    
    enum OrderType {
        case market, limit
    }
}

struct APIResponse<T: Codable>: Codable {
    let success: Bool
    let data: T?
    let error: String?
}

struct QuoteResponse: Codable {
