class SecureAPIClient {
    static let shared = SecureAPIClient()
    private let baseURL = "https://api.trading-platform.com/v1"
    private var apiKey: String?
    private var authToken: String?
    
    private init() {}
    
    func setCredentials(apiKey: String, authToken: String) {
        self.apiKey = apiKey
        self.authToken = authToken
    }
    
    private func createRequest(endpoint: String, method: String = "GET", body: Data? = nil) -> URLRequest? {
        guard let url = URL(string: baseURL + endpoint) else { return nil }
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if let apiKey = apiKey {
            request.setValue(apiKey, forHTTPHeaderField: "X-API-Key")
        }
        if let authToken = authToken {
            request.setValue("Bearer \(authToken)", forHTTPHeaderField: "Authorization")
        }
        
        request.httpBody = body
        return request
    }
    
    func fetchStockQuote(symbol: String, completion: @escaping (Result<Stock, Error>) -> Void) {
        guard let request = createRequest(endpoint: "/stocks/\(symbol)") else {
            completion(.failure(NetworkError.invalidRequest))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let apiResponse = try JSONDecoder().decode(APIResponse<Stock>.self, from: data)
                if apiResponse.success, let stock = apiResponse.data {
                    completion(.success(stock))
                } else {
                    completion(.failure(NetworkError.apiError(apiResponse.error ?? "Unknown error")))
                }
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    func executeTrade(order: TradeOrder, completion: @escaping (Result<Trade, Error>) -> Void) {
        let orderData: [String: Any] = [
            "symbol": order.stockSymbol,
            "type": order.type.rawValue,
            "quantity": order.quantity,
            "order_type": order.orderType == .market ? "market" : "limit",
            "limit_price": order.limitPrice as Any
        ]
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: orderData),
              let request = createRequest(endpoint: "/trades", method: "POST", body: jsonData) else {
            completion(.failure(NetworkError.invalidRequest))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let apiResponse = try JSONDecoder().decode(APIResponse<Trade>.self, from: data)
                if apiResponse.success, let trade = apiResponse.data {
                    completion(.success(trade))
                } else {
                    completion(.failure(NetworkError.apiError(apiResponse.error ?? "Trade execution failed")))
                }
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    func fetchPortfolio(completion: @escaping (Result<Portfolio, Error>) -> Void) {
        guard let request = createRequest(endpoint: "/portfolio") else {
            completion(.failure(NetworkError.invalidRequest))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let apiResponse = try JSONDecoder().decode(APIResponse<Portfolio>.self, from: data)
                if apiResponse.success, let portfolio = apiResponse.data {
                    completion(.success(portfolio))
                } else {
                    completion(.failure(NetworkError.apiError(apiResponse.error ?? "Failed to fetch portfolio")))
                }
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    func fetchTradeHistory(completion: @escaping (Result<[Trade], Error>) -> Void) {
        guard let request = createRequest(endpoint: "/trades/history") else {
            completion(.failure(NetworkError.invalidRequest))
            return
        }
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NetworkError.noData))
                return
            }
            
            do {
                let apiResponse = try JSONDecoder().decode(APIResponse<[Trade]>.self, from: data)
                if apiResponse.success, let trades = apiResponse.data {
                    completion(.success(trades))
                } else {
                    completion(.failure(NetworkError.apiError(apiResponse.error ?? "Failed to fetch trade history")))
                }
            } catch {
                completion(.failure(error))
            }
        }.resume()
    }
    
    enum NetworkError: LocalizedError {
        case invalidRequest
        case noData
        case apiError(String)
        
        var errorDescription: String? {
            switch self {
            case .invalidRequest: return "Invalid request"
            case .noData: return "No data received"
            case .apiError(let message): return message
            }
        }
    }
}

// MARK: - Portfolio Manager

class PortfolioManager: ObservableObject {
    @Published var portfolio: Portfolio?
    @Published var isLoading = false
    @Published var error: String?
    
    private var cancellables = Set<AnyCancellable>()
    
    func loadPortfolio() {
        isLoading = true
        error = nil
        
        SecureAPIClient.shared.fetchPortfolio { [weak self] result in
            DispatchQueue.main.async {
                self?.isLoading = false
                switch result {
                case .success(let portfolio):
                    self?.portfolio = portfolio
                case .failure(let error):
                    self?.error = error.localizedDescription
                }
            }
        }
    }
    
    func updateHoldingPrices(for stocks: [Stock]) {
        guard var currentPortfolio = portfolio else { return }
        
        for stock in stocks {
            if let index = currentPortfolio.holdings.firstIndex(where: { $0.stockSymbol == stock.symbol }) {
                currentPortfolio.holdings[index].currentPrice = stock.currentPrice
            }
        }
        
        portfolio = currentPortfolio
    }
}

// MARK: - Trading Engine

class TradingEngine: ObservableObject {
    @Published var pendingOrders: [TradeOrder] = []
    @Published var recentTrades: [Trade] = []
    @Published var isExecuting = false
    @Published var error: String?
    
    private let portfolioManager: PortfolioManager
    
    init(portfolioManager: PortfolioManager) {
        self.portfolioManager = portfolioManager
    }
    
    func executeTrade(order: TradeOrder, completion: @escaping (Bool) -> Void) {
        guard validateOrder(order) else {
            error = "Invalid order parameters"
            completion(false)
            return
        }
        
        isExecuting = true
        error = nil
        
        SecureAPIClient.shared.executeTrade(order: order) { [weak self] result in
            DispatchQueue.main.async {
                self?.isExecuting = false
                switch result {
                case .success(let trade):
                    self?.recentTrades.insert(trade, at: 0)
                    self?.portfolioManager.loadPortfolio()
                    completion(true)
                case .failure(let error):
                    self?.error = error.localizedDescription
                    completion(false)
                }
            }
        }
    }
    
    private func validateOrder(_ order: TradeOrder) -> Bool {
        guard order.quantity > 0 else { return false }
        
        if order.orderType == .limit {
            guard let limitPrice = order.limitPrice, limitPrice > 0 else {
                return false
            }
        }
        
        guard let portfolio = portfolioManager.portfolio else { return false }
        
        if order.type == .sell {
            if let holding = portfolio.holdings.first(where: { $0.stockSymbol == order.stockSymbol }) {
                return holding.quantity >= order.quantity
            }
            return false
        }
        
        return true
    }
    
    func loadTradeHistory() {
        SecureAPIClient.shared.fetchTradeHistory { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let trades):
                    self?.recentTrades = trades
                case .failure(let error):
                    self?.error = error.localizedDescription
                }
            }
        }
    }
}

// MARK: - Real-time Price Manager

class RealTimePriceManager: ObservableObject {
    @Published var stocks: [String: Stock] = [:]
    @Published var isConnected = false
    
    private var timer: Timer?
    private var watchlist: Set<String> = []
    
    func addToWatchlist(_ symbol: String) {
        watchlist.insert(symbol)
        fetchQuote(for: symbol)
    }
    
    func removeFromWatchlist(_ symbol: String) {
        watchlist.remove(symbol)
        stocks.removeValue(forKey: symbol)
    }
    
    func startPriceUpdates() {
        timer?.invalidate()
        timer = Timer.scheduledTimer(withTimeInterval: 5.0, repeats: true) { [weak self] _ in
            self?.updateAllPrices()
        }
        isConnected = true
    }
    
    func stopPriceUpdates() {
        timer?.invalidate()
        timer = nil
        isConnected = false
    }
    
    private func updateAllPrices() {
        for symbol in watchlist {
            fetchQuote(for: symbol)
        }
    }
    
    private func fetchQuote(for symbol: String) {
        SecureAPIClient.shared.fetchStockQuote(symbol: symbol) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let stock):
                    self?.stocks[symbol] = stock
                case .failure:
                    break
                }
            }
        }
    }
}

