class PortfolioViewController: UIViewController {
    private let tableView = UITableView(frame: .zero, style: .grouped)
    private let portfolioManager = PortfolioManager()
    private let priceManager = RealTimePriceManager()
    private var cancellables = Set<AnyCancellable>()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupBindings()
        portfolioManager.loadPortfolio()
        priceManager.startPriceUpdates()
    }
    
    private func setupUI() {
        title = "Portfolio"
        view.backgroundColor = .systemBackground
        
        tableView.translatesAutoresizingMaskIntoConstraints = false
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(PortfolioHeaderView.self, forHeaderFooterViewReuseIdentifier: "Header")
        tableView.register(HoldingCell.self, forCellReuseIdentifier: "HoldingCell")
        
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .refresh, target: self, action: #selector(refreshPortfolio))
    }
    
    private func setupBindings() {
        portfolioManager.$portfolio
            .receive(on: DispatchQueue.main)
            .sink { [weak self] portfolio in
                self?.tableView.reloadData()
                if let holdings = portfolio?.holdings {
                    for holding in holdings {
                        self?.priceManager.addToWatchlist(holding.stockSymbol)
                    }
                }
            }
            .store(in: &cancellables)
        
        priceManager.$stocks
            .receive(on: DispatchQueue.main)
            .sink { [weak self] stocks in
                self?.portfolioManager.updateHoldingPrices(for: Array(stocks.values))
                self?.tableView.reloadData()
            }
            .store(in: &cancellables)
    }
    
    @objc private func refreshPortfolio() {
        portfolioManager.loadPortfolio()
    }
}

extension PortfolioViewController: UITableViewDelegate, UITableViewDataSource {
    func numberOfSections(in tableView: UITableView) -> Int {
        return 1
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return portfolioManager.portfolio?.holdings.count ?? 0
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "HoldingCell", for: indexPath) as! HoldingCell
        if let holding = portfolioManager.portfolio?.holdings[indexPath.row] {
            cell.configure(with: holding)
        }
        return cell
    }
    
    func tableView(_ tableView: UITableView, viewForHeaderInSection section: Int) -> UIView? {
        let header = tableView.dequeueReusableHeaderFooterView(withIdentifier: "Header") as! PortfolioHeaderView
        if let portfolio = portfolioManager.portfolio {
            header.configure(with: portfolio)
        }
        return header
    }
    
    func tableView(_ tableView: UITableView, heightForHeaderInSection section: Int) -> CGFloat {
        return 120
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        if let holding = portfolioManager.portfolio?.holdings[indexPath.row] {
            let tradeVC = TradeViewController(stockSymbol: holding.stockSymbol, portfolioManager: portfolioManager)
            navigationController?.pushViewController(tradeVC, animated: true)
        }
    }
}

// MARK: - Trade View Controller

class TradeViewController: UIViewController {
    private let stockSymbol: String
    private let portfolioManager: PortfolioManager
    private lazy var tradingEngine = TradingEngine(portfolioManager: portfolioManager)
    private let priceManager = RealTimePriceManager()
    
    private let symbolLabel = UILabel()
    private let priceLabel = UILabel()
    private let changeLabel = UILabel()
    private let tradeTypeSegment = UISegmentedControl(items: ["Buy", "Sell"])
    private let quantityTextField = UITextField()
    private let orderTypeSegment = UISegmentedControl(items: ["Market", "Limit"])
    private let limitPriceTextField = UITextField()
    private let estimatedCostLabel = UILabel()
    private let executeButton = UIButton(type: .system)
    
    private var cancellables = Set<AnyCancellable>()
    private var currentStock: Stock?
    
    init(stockSymbol: String, portfolioManager: PortfolioManager) {
        self.stockSymbol = stockSymbol
        self.portfolioManager = portfolioManager
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        setupBindings()
        priceManager.addToWatchlist(stockSymbol)
        priceManager.startPriceUpdates()
    }
    
    private func setupUI() {
        title = "Trade"
        view.backgroundColor = .systemBackground
        
        let stackView = UIStackView()
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        symbolLabel.font = .systemFont(ofSize: 32, weight: .bold)
        symbolLabel.text = stockSymbol
        
        priceLabel.font = .systemFont(ofSize: 24, weight: .semibold)
        
        changeLabel.font = .systemFont(ofSize: 16)
        
        tradeTypeSegment.selectedSegmentIndex = 0
        
        quantityTextField.placeholder = "Quantity"
        quantityTextField.keyboardType = .numberPad
        quantityTextField.borderStyle = .roundedRect
        quantityTextField.addTarget(self, action: #selector(updateEstimate), for: .editingChanged)
        
        orderTypeSegment.selectedSegmentIndex = 0
        orderTypeSegment.addTarget(self, action: #selector(orderTypeChanged), for: .valueChanged)
        
        limitPriceTextField.placeholder = "Limit Price"
        limitPriceTextField.keyboardType = .decimalPad
        limitPriceTextField.borderStyle = .roundedRect
        limitPriceTextField.isHidden = true
        limitPriceTextField.addTarget(self, action: #selector(updateEstimate), for: .editingChanged)
        
        estimatedCostLabel.font = .systemFont(ofSize: 18, weight: .medium)
        estimatedCostLabel.textAlignment = .center
        
        executeButton.setTitle("Execute Trade", for: .normal)
        executeButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .bold)
        executeButton.backgroundColor = .systemBlue
        executeButton.setTitleColor(.white, for: .normal)
        executeButton.layer.cornerRadius = 10
        executeButton.addTarget(self, action: #selector(executeTrade), for: .touchUpInside)
        
        stackView.addArrangedSubview(symbolLabel)
        stackView.addArrangedSubview(priceLabel)
        stackView.addArrangedSubview(changeLabel)
        stackView.addArrangedSubview(tradeTypeSegment)
        stackView.addArrangedSubview(quantityTextField)
        stackView.addArrangedSubview(orderTypeSegment)
        stackView.addArrangedSubview(limitPriceTextField)
        stackView.addArrangedSubview(estimatedCostLabel)
        stackView.addArrangedSubview(executeButton)
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            executeButton.heightAnchor.constraint(equalToConstant: 50)
        ])
    }
    
    private func setupBindings() {
        priceManager.$stocks
            .receive(on: DispatchQueue.main)
            .sink { [weak self] stocks in
                guard let self = self, let stock = stocks[self.stockSymbol] else { return }
                self.currentStock = stock
                self.updateStockDisplay(stock)
                self.updateEstimate()
            }
            .store(in: &cancellables)
        
        tradingEngine.$isExecuting
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isExecuting in
                self?.executeButton.isEnabled = !isExecuting
                self?.executeButton.alpha = isExecuting ? 0.5 : 1.0
            }
            .store(in: &cancellables)
    }
    
    private func updateStockDisplay(_ stock: Stock) {
        priceLabel.text = String(format: "$%.2f", stock.currentPrice)
        
        let changeText = String(format: "%.2f%%", stock.changePercent)
        changeLabel.text = stock.changePercent >= 0 ? "+\(changeText)" : changeText
        changeLabel.textColor = stock.changePercent >= 0 ? .systemGreen : .systemRed
    }
    
    @objc private func orderTypeChanged() {
        limitPriceTextField.isHidden = orderTypeSegment.selectedSegmentIndex == 0
        updateEstimate()
    }
    
    @objc private func updateEstimate() {
        guard let quantityText = quantityTextField.text,
              let quantity = Int(quantityText),
              quantity > 0 else {
            estimatedCostLabel.text = ""
            return
        }
        
        let price: Double
        if orderTypeSegment.selectedSegmentIndex == 1,
           let limitText = limitPriceTextField.text,
           let limitPrice = Double(limitText) {
            price = limitPrice
        } else if let stock = currentStock {
            price = stock.currentPrice
        } else {
            estimatedCostLabel.text = ""
            return
        }
        
        let total = price * Double(quantity)
        let action = tradeTypeSegment.selectedSegmentIndex == 0 ? "Cost" : "Proceeds"
        estimatedCostLabel.text = String(format: "Estimated %@: $%.2f", action, total)
    }
    
    @objc private func executeTrade() {
        guard let quantityText = quantityTextField.text,
              let quantity = Int(quantityText),
              quantity > 0 else {
            showAlert(title: "Invalid Quantity", message: "Please enter a valid quantity")
            return
        }
        
        let tradeType: Trade.TradeType = tradeTypeSegment.selectedSegmentIndex == 0 ? .buy : .sell
        let orderType: TradeOrder.OrderType = orderTypeSegment.selectedSegmentIndex == 0 ? .market : .limit
        
        var limitPrice: Double?
        if orderType == .limit {
            guard let limitText = limitPriceTextField.text,
                  let price = Double(limitText),
                  price > 0 else {
                showAlert(title: "Invalid Price", message: "Please enter a valid limit price")
                return
            }
            limitPrice = price
        }
        
        let order = TradeOrder(
            stockSymbol: stockSymbol,
            type: tradeType,
            quantity: quantity,
            orderType: orderType,
            limitPrice: limitPrice
        )
        
        let confirmMessage = String(format: "%@ %d shares of %@ at %@?",
                                   tradeType == .buy ? "Buy" : "Sell",
                                   quantity,
                                   stockSymbol,
                                   orderType == .market ? "market price" : String(format: "$%.2f", limitPrice ?? 0))
        
        let alert = UIAlertController(title: "Confirm Trade", message: confirmMessage, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Confirm", style: .default) { [weak self] _ in
            self?.performTrade(order)
        })
        present(alert, animated: true)
    }
    
    private func performTrade(_ order: TradeOrder) {
        tradingEngine.executeTrade(order: order) { [weak self] success in
            DispatchQueue.main.async {
                if success {
                    self?.showAlert(title: "Success", message: "Trade executed successfully") {
                        self?.navigationController?.popViewController(animated: true)
                    }
                } else if let error = self?.tradingEngine.error {
                    self?.showAlert(title: "Trade Failed", message: error)
                }
            }
        }
    }
    
    private func showAlert(title: String, message: String, completion: (() -> Void)? = nil) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completion?()
        })
        present(alert, animated: true)
    }
}

